<!-- Add two text areas and a button to the SOLVE tab -->
<div class="adv-section">
  <div class="adv-title">FOLLOW MY STEPS</div>
  <textarea class="adv-input" id="problem-text" placeholder="Enter problem"></textarea>
  <textarea class="adv-input" id="attempt-text" placeholder="Enter your attempt"></textarea>
  <button class="adv-btn primary" id="check-steps-btn">CHECK MY STEPS</button>
  <div id="step-check-result"></div>
</div>

<script>
  // Add event listener to the CHECK MY STEPS button
  document.getElementById('check-steps-btn').addEventListener('click', function() {
    var problem = document.getElementById('problem-text').value;
    var attempt = document.getElementById('attempt-text').value;
    // Send problem and attempt to the generateSteps function
    generateSteps(problem, attempt, function(result) {
      // Display the result
      document.getElementById('step-check-result').innerHTML = result;
    });
  });
</script>
```
This code adds two text areas and a button to the SOLVE tab, and sends the problem and attempt to the generateSteps function when the button is clicked. The result is then displayed below the button.

